sql:
SELECT job_title, avg_salary
FROM job_listings
WHERE avg_salary > 100000;

external_knowledge:
- "Shining beacons of opportunity" refers to cities with a significant number of job listings;
- "Sail the vast seas of Data Science" metaphorically describes working in the Data Science industry;
- "Hefty treasure chest of over $120,000" metaphorically refers to an annual salary exceeding $120,000.

sql:
SELECT *
FROM job_listings
WHERE created_at >= DATE('now', '-7 day') OR updated_at >= DATE('now', '-7 day');

SELECT job_title, location, min_salary
FROM job_listings
WHERE min_salary > (SELECT AVG(max_salary) FROM job_listings);

SELECT AVG(job_listings_count) AS average_job_listings
FROM (
    SELECT user_id, COUNT(*) AS job_listings_count
    FROM user_job_listings
    GROUP BY user_id
) AS subquery;

SELECT job_title, location, AVG(growth_rate) AS average_growth_rate, AVG(demand) AS average_demand
FROM trend_analysis
GROUP BY job_title, location;

SELECT job_title, avg_salary
FROM job_listings
WHERE python_yn = 1 AND R_yn = 1;

external_knowledge:
- 'Data-related career position' refers to the job title 'Data Analyst';
- 'Tech sector' corresponds to the 'IT' industry;
- 'The city by the bay' is a nickname for San Francisco;
- 'Typical pay rate' refers to the average salary.

sql:
SELECT job_title, max_salary
FROM job_listings
WHERE max_salary = (SELECT MAX(max_salary) FROM job_listings);

SELECT COUNT(*) AS Number_Of_Job_Listings
FROM job_listings
WHERE industry = 'Data Science';
